class Solution:
    def validSubstringCount(self, word1: str, word2: str) -> int:
        count = 0
        for i in range(len(word1)):
            freq1 = {}
            freq2 = {}
            for j in range(i, len(word1)):
                freq1[word1[j]] = freq1.get(word1[j], 0) + 1
                for k in range(len(word2)):
                    freq2[word2[k]] = freq2.get(word2[k], 0) + 1
                if all(freq1.get(c, 0) >= freq2.get(c, 0) for c in freq2):
                    count += 1
        return count
